if "step" not in st.session_state:
    st.session_state.step = 0
if "data" not in st.session_state:
    st.session_state.data = {}
if "rate" not in st.session_state:
    st.session_state.rate = {"USD": 4600, "EUR": 5000}

TOTAL = len(STEPS)

# ══════════════════════════════════════════════════════════════════════
#  UTILITIES
# ══════════════════════════════════════════════════════════════════════
def fmt_ar(n):
    try:
        return f"{int(n):,} Ar".replace(",", " ")
    except:
        return "0 Ar"

def next_step(): st.session_state.step += 1
def prev_step(): st.session_state.step -= 1

def f(label, key, ph="", multi=False, h=""):
    val = st.session_state.data.get(key, "")
    if multi:
        r = st.text_area(label, value=val, placeholder=ph, help=h, height=115)
    else:
        r = st.text_input(label, value=val, placeholder=ph, help=h)
    st.session_state.data[key] = r
    return r

def n(label, key, mn=0, mx=2_000_000_000, step=100_000, default=0):
    val = int(st.session_state.data.get(key, default) or default)
    r = st.number_input(label, min_value=mn, max_value=mx, value=val, step=step, format="%d")
    st.session_state.data[key] = r
    return r

def sel(label, key, opts, h=""):
    val = st.session_state.data.get(key, opts[0])
    idx = opts.index(val) if val in opts else 0
    r = st.selectbox(label, opts, index=idx, help=h)
    st.session_state.data[key] = r
    return r

def radio(label, key, opts):
    val = st.session_state.data.get(key, opts[0])
    idx = opts.index(val) if val in opts else 0
    r = st.radio(label, opts, index=idx, horizontal=True)
    st.session_state.data[key] = r
    return r

def msel(label, key, opts):
    val = st.session_state.data.get(key, [])
    r = st.multiselect(label, opts, default=val)
    st.session_state.data[key] = r
    return r

def tip(txt):
    st.markdown(f'<div class="tip">💡 {txt}</div>', unsafe_allow_html=True)

def warn(txt):
    st.markdown(f'<div class="warn">⚠️ {txt}</div>', unsafe_allow_html=True)

def gc_open(icon, title, sub=""):
    st.markdown(f"""<div class="gc">
    <div class="gc-ttl">{icon} {title}</div>
    {"<div class='gc-sub'>" + sub + "</div>" if sub else ""}""", unsafe_allow_html=True)

def nav(show_prev=True):
    c1, _, c3 = st.columns([1, 3, 1])
    if show_prev:
        with c1:
            if st.button("◀ Retour", key=f"prev_{st.session_state.step}"):
                prev_step()
    with c3:
        if st.button("Suivant ▶", key=f"next_{st.session_state.step}"):
            next_step()

# ══════════════════════════════════════════════════════════════════════
#  EXCHANGE RATE (free API)
# ══════════════════════════════════════════════════════════════════════
@st.cache_data(ttl=3600)
def fetch_rates():
    try:
        r = requests.get("https://open.er-api.com/v6/latest/USD", timeout=6)
        data = r.json()
        mga = data["rates"].get("MGA", 4600)
        eur_rate = data["rates"].get("EUR", 0.92)
        return {"USD": int(mga), "EUR": int(mga / eur_rate)}
    except:
        return {"USD": 4600, "EUR": 5000}

# ══════════════════════════════════════════════════════════════════════
#  AI SUGGESTIONS (Anthropic API)
# ══════════════════════════════════════════════════════════════════════
def call_claude(prompt: str, api_key: str) -> str:
    try:
        r = requests.post(
            "https://api.anthropic.com/v1/messages",
            headers={
                "x-api-key": api_key,
                "anthropic-version": "2023-06-01",
                "content-type": "application/json"
            },
            json={
                "model": "claude-sonnet-4-6",
                "max_tokens": 600,
                "messages": [{"role": "user", "content": prompt}]
            },
            timeout=20
        )
        if r.status_code == 200:
            return r.json()["content"][0]["text"]
        return f"Erreur API {r.status_code}"
    except Exception as e:
        return f"Erreur : {str(e)}"

def ai_box(section: str, context: str = ""):
    api_key = st.session_state.get("api_key", "")
    nom = st.session_state.data.get("nom_projet", "mon projet")
    secteur = st.session_state.data.get("secteur", "")
    region = st.session_state.data.get("region", "Madagascar")

    with st.expander("✨ Suggestion IA — Cliquez pour obtenir de l'aide"):
        if not api_key:
            st.markdown('<div class="warn">🔑 Entrez votre clé API Anthropic dans la barre latérale pour activer les suggestions IA.</div>', unsafe_allow_html=True)
            return
        if st.button(f"🚀 Générer une suggestion pour : {section}", key=f"ai_{section}_{st.session_state.step}"):
            with st.spinner("L'IA consultant analyse votre projet..."):
                prompt = f"""Tu es un consultant en business plan spécialisé à Madagascar.
Projet : {nom} | Secteur : {secteur} | Région : {region}
{context}
Donne une suggestion professionnelle et concrète pour la section '{section}' d'un business plan malgache.
Prends en compte le contexte local (économie malgache, bailleurs de fonds AFD/BNI, monnaie Ariary).
Sois concis (3-5 phrases), pratique et adapté à Madagascar. Réponds en français."""
                result = call_claude(prompt, api_key)
                st.markdown(f'<div class="ai-tip">🤖 {result}</div>', unsafe_allow_html=True)

