# ══════════════════════════════════════════════════════════════════════
#  PROGRESS HEADER
# ══════════════════════════════════════════════════════════════════════
def render_progress():
    step = st.session_state.step
    if step == 0:
        return
    pct = int((step / (TOTAL - 1)) * 100)
    st.markdown(f"""
    <div class="prog-wrap">
      <div class="prog-meta"><span>Étape {step} sur {TOTAL-1}</span><span>{pct}%</span></div>
      <div class="prog-track"><div class="prog-fill" style="width:{pct}%"></div></div>
    </div>""", unsafe_allow_html=True)

    dots = ""
    for i, s in enumerate(STEPS):
        cls = "done" if i < step else ("active" if i == step else "pend")
        dots += f'<span class="sp {cls}">{s}</span>'
    st.markdown(f'<div class="step-nav">{dots}</div>', unsafe_allow_html=True)

