def step_team():
    st.markdown('<div class="gc"><div class="gc-ttl">👥 L\'Équipe</div><div class="gc-sub">Les bailleurs investissent d\'abord dans les personnes. Valorisez votre équipe.</div>', unsafe_allow_html=True)
