    for i in range(1, nb + 1):
        st.markdown(f"**👤 {'Fondateur principal' if i==1 else f'Co-fondateur {i}'}**")
        c1, c2 = st.columns(2)
        with c1:
            f(f"Nom complet", f"f{i}_nom", "Ex : Rasoa Marie")
            f(f"Rôle dans l'entreprise", f"f{i}_role", "Ex : Directrice Générale / Production")
        with c2:
            f(f"Formation / Diplôme", f"f{i}_formation", "Ex : Ingénieur Agronome ESSA Tana")
            f(f"Expérience clé (années + domaine)", f"f{i}_experience", "Ex : 8 ans en agrobusiness, ex-responsable CECAM")
        f(f"Compétences apportées au projet", f"f{i}_competences",
          "Ex : Réseau paysans, maîtrise du foncier, gestion coopératives")
