#  STEP 9 — PROJECTIONS 5 ANS
# ══════════════════════════════════════════════════════════════════════
def step_projections():
    st.markdown('<div class="gc"><div class="gc-ttl">📊 Projections Financières — 5 Ans</div><div class="gc-sub">Toutes les valeurs en Ariary (Ar). Les banques malgaches exigent minimum 3 ans, les bailleurs 5 ans.</div>', unsafe_allow_html=True)
    tip("Soyez réaliste et conservateur. Une croissance de 20-40%/an est crédible. Évitez les courbes « hockey stick ».")
    ai_box("Projections Financières Madagascar",
           f"Modèle : {st.session_state.data.get('modele_eco','')}")

    st.markdown("**📈 Chiffre d'affaires prévisionnel (Ar)**")
    c1, c2, c3, c4, c5 = st.columns(5)
    cas = []
    for i, (col, yr) in enumerate(zip([c1,c2,c3,c4,c5], range(1,6))):
        with col:
            v = n(f"An {yr}", f"ca_an{yr}", step=500_000, default=0)
            cas.append(v)

    # Show KPIs
    if cas[0] > 0:
        growth_35 = f"+{int((cas[4]/cas[0]-1)*100)}%" if cas[0] > 0 else "—"
        st.markdown(f"""
        <div class="kpi-row">
          <div class="kpi g"><div class="kpi-val">{fmt_ar(cas[0])}</div><div class="kpi-lbl">CA An 1</div></div>
          <div class="kpi g"><div class="kpi-val">{fmt_ar(cas[2])}</div><div class="kpi-lbl">CA An 3</div></div>
          <div class="kpi y"><div class="kpi-val">{fmt_ar(cas[4])}</div><div class="kpi-lbl">CA An 5</div></div>
          <div class="kpi p"><div class="kpi-val">{growth_35}</div><div class="kpi-lbl">Croissance An1→An5</div></div>
        </div>
        """, unsafe_allow_html=True)

    st.markdown("**💸 Charges fixes mensuelles (Ar/mois)**")
    c1, c2, c3 = st.columns(3)
    with c1:
        n("👔 Salaires et charges sociales", "ch_salaires", step=100_000, default=0)
        n("🏠 Loyer / domiciliation", "ch_loyer", step=50_000, default=0)
    with c2:
        n("🚗 Transport / carburant", "ch_transport", step=50_000, default=0)
        n("📱 Télécoms / internet / électricité", "ch_telecom", step=20_000, default=0)
    with c3:
        n("📊 Comptabilité / conseils juridiques", "ch_compta", step=50_000, default=0)
        n("📣 Marketing / communication", "ch_marketing", step=50_000, default=0)

    n("🔧 Autres charges fixes / mois (Ar)", "ch_autres", step=20_000, default=0)

    st.markdown("**📉 Charges variables (% du CA)**")
    c1, c2, c3 = st.columns(3)
    with c1:
        n("Coût des ventes / COGS (%)", "cogs_pct", mn=0, mx=90, step=1, default=30)
    with c2:
        n("Commissions / frais livraison (%)", "comm_pct", mn=0, mx=30, step=1, default=5)
    with c3:
        n("Taxes / impôts sur CA (%)", "taxe_pct", mn=0, mx=30, step=1, default=5)

    st.markdown("**💡 Point mort estimé**")
    ch_fixes_mois = sum([
        int(st.session_state.data.get(k, 0) or 0)
        for k in ["ch_salaires","ch_loyer","ch_transport","ch_telecom","ch_compta","ch_marketing","ch_autres"]
    ])
    ch_var_pct = (int(st.session_state.data.get("cogs_pct",30) or 30)
                 + int(st.session_state.data.get("comm_pct",5) or 5)
                 + int(st.session_state.data.get("taxe_pct",5) or 5)) / 100
    if ch_var_pct < 1 and ch_fixes_mois > 0:
        pm_mois = ch_fixes_mois / (1 - ch_var_pct)
        pm_an = pm_mois * 12
        st.markdown(f"""
        <div class="kpi-row">
          <div class="kpi y"><div class="kpi-val">{fmt_ar(pm_mois)}</div><div class="kpi-lbl">Point mort / mois</div></div>
          <div class="kpi y"><div class="kpi-val">{fmt_ar(pm_an)}</div><div class="kpi-lbl">Point mort / an</div></div>
          <div class="kpi g"><div class="kpi-val">{fmt_ar(ch_fixes_mois)}</div><div class="kpi-lbl">Charges fixes / mois</div></div>
          <div class="kpi r"><div class="kpi-val">{int((1-ch_var_pct)*100)}%</div><div class="kpi-lbl">Marge sur CV</div></div>
        </div>
        """, unsafe_allow_html=True)
    st.markdown('</div>', unsafe_allow_html=True)
    nav()

